@mixin --foo(--arg <length>) {
  @result {
    &, & > h2, & + p {
      width: var(--arg);
    }
  }
}

div {
  @apply --foo(10em);
  font-size: 10px;
}
div > h2 {
  font-size: 20px;
}
div + p {
  font-size: 30px;
}

